// PlayoffsMenu.js
import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

function PlayoffsMenu() {
    const [ligaSeleccionada, setLigaSeleccionada] = useState("");
    const [playoffs, setPlayoffs] = useState({});
    const [rondas, setRondas] = useState([]);
    const [rondaActiva, setRondaActiva] = useState(0);
    const navigate = useNavigate();

    useEffect(() => {
        const stored = JSON.parse(localStorage.getItem("playoffs_brackets")) || {};
        setPlayoffs(stored);
        const ligas = Object.keys(stored);
        if (ligas.length > 0) {
            setLigaSeleccionada(ligas[0]);
            setRondas(stored[ligas[0]]);
        }
    }, []);

    useEffect(() => {
        if (ligaSeleccionada && playoffs[ligaSeleccionada]) {
            setRondas(playoffs[ligaSeleccionada]);
            setRondaActiva(0);
        }
    }, [ligaSeleccionada]);

    const jugarPartido = (match, i) => {
        if (match.jugado) return;

        const golesLocal = Math.floor(Math.random() * 4);
        const golesVisitante = Math.floor(Math.random() * 4);

        const nuevaRonda = [...rondas[rondaActiva]];
        nuevaRonda[i] = { ...match, golesLocal, golesVisitante, jugado: true };

        const nuevasRondas = [...rondas];
        nuevasRondas[rondaActiva] = nuevaRonda;

        const updatedPlayoffs = { ...playoffs };
        updatedPlayoffs[ligaSeleccionada] = nuevasRondas;

        setRondas(nuevasRondas);
        setPlayoffs(updatedPlayoffs);
        localStorage.setItem("playoffs_brackets", JSON.stringify(updatedPlayoffs));
    };

    const avanzarRonda = () => {
        const rondaActual = rondas[rondaActiva];
        if (!rondaActual.every(p => p.jugado)) {
            alert("Debes jugar todos los partidos de esta ronda.");
            return;
        }

        const ganadores = rondaActual.map(p =>
            p.golesLocal > p.golesVisitante ? p.local : p.visitante
        );

        // En Tercera RFEF ronda2 ya está predefinida
        if (ligaSeleccionada === "Tercera RFEF" && rondaActiva === 0 && playoffs["Tercera RFEF"].ronda2) {
            setRondaActiva(1);
            return;
        }

        if (ganadores.length < 2) {
            alert("Finalizados los playoffs.");
            return;
        }

        const nuevaRonda = [];
        for (let i = 0; i < ganadores.length; i += 2) {
            if (ganadores[i + 1]) {
                nuevaRonda.push({
                    local: ganadores[i],
                    visitante: ganadores[i + 1],
                    golesLocal: null,
                    golesVisitante: null,
                    jugado: false
                });
            }
        }

        const nuevasRondas = [...rondas, nuevaRonda];
        const updatedPlayoffs = { ...playoffs };
        updatedPlayoffs[ligaSeleccionada] = nuevasRondas;

        setRondas(nuevasRondas);
        setPlayoffs(updatedPlayoffs);
        setRondaActiva(rondaActiva + 1);
        localStorage.setItem("playoffs_brackets", JSON.stringify(updatedPlayoffs));
    };

    const finalizarPlayoffs = () => {
        // Acá se debe:
        // - Cambiar ligas en localStorage.equipos según ganadores/perdedores
        // - Llamar a LeagueGeneration.js para nueva temporada
        alert("Ascensos/descensos aplicados. Comienza nueva temporada.");
        navigate("/generar-ligas");
    };

    const renderMatch = (match, i) => (
        <div key={i} className="match-card">
            <span>{match.local?.nombre} {match.golesLocal ?? "-"} vs {match.golesVisitante ?? "-"} {match.visitante?.nombre}</span>
            {!match.jugado && (
                <button onClick={() => jugarPartido(match, i)}>Jugar</button>
            )}
        </div>
    );

    return (
        <div className="playoffs-menu">
            <h1>Playoffs</h1>
            <select value={ligaSeleccionada} onChange={(e) => setLigaSeleccionada(e.target.value)}>
                {Object.keys(playoffs).map((liga, i) => (
                    <option key={i} value={liga}>{liga}</option>
                ))}
            </select>

            <h2>Ronda {rondaActiva + 1}</h2>
            <div className="ronda-matches">
                {Array.isArray(rondas[rondaActiva]) &&
                    rondas[rondaActiva].map((match, i) => renderMatch(match, i))}
            </div>

            <div className="playoff-controls">
                <button onClick={avanzarRonda}>Avanzar Ronda</button>
                <button onClick={finalizarPlayoffs}>Finalizar Playoffs</button>
            </div>
        </div>
    );
}

export default PlayoffsMenu;
